   217→function parseDouyinData(rawData) {
   218→    try {
   219→        if (rawData.method === 'video_tag') {
   220→            return {
   221→                title: rawData.title || '抖音视频',
   222→                videoUrl: rawData.videoUrl,
   223→                desc: rawData.title || ''
   224→            };
   225→        }
   226→
   227→        const data = JSON.parse(rawData.data);
   228→
   229→        // RENDER_DATA 格式
   230→        if (rawData.method === 'RENDER_DATA') {
   231→            // 遍历所有 key 找视频数据
   232→            for (const key of Object.keys(data)) {
   233→                const section = data[key];
   234→                // 查找 aweme detail
   235→                const detail = section?.awemeDetail || section?.videoInfoRes?.item_list?.[0];
   236→                if (detail) {
   237→                    const video = detail.video || {};
   238→                    const playAddr = video.play_addr || video.playAddr || {};
   239→                    const urlList = playAddr.url_list || [];
   240→                    const videoUrl = urlList[0] || video.download_addr?.url_list?.[0];
   241→                    return {
   242→                        title: detail.desc || '抖音视频',
   243→                        desc: detail.desc || '',
   244→                        author: detail.author?.nickname || '',
   245→                        duration: video.duration ? video.duration / 1000 : 0,
   246→                        videoUrl: videoUrl
   247→                    };
   248→                }
   249→            }
   250→        }
   251→
   252→        // SSR 格式
   253→        if (rawData.method === 'SSR') {
   254→            const detail = data?.anyVideo?.videoInfoRes?.item_list?.[0] ||
   255→                          data?.videoDetail?.videoInfo;
   256→            if (detail) {
   257→                const video = detail.video || {};
   258→                const playAddr = video.play_addr || {};
   259→                const urlList = playAddr.url_list || [];
   260→                return {
   261→                    title: detail.desc || '抖音视频',
   262→                    desc: detail.desc || '',
   263→                    author: detail.author?.nickname || '',
   264→                    videoUrl: urlList[0]
   265→                };
   266→            }
   267→        }
   268→
   269→        return null;
   270→    } catch (e) {
   271→        console.error('解析抖音数据失败:', e.message);
   272→        return null;
   273→    }
   274→}
