   362→function baseArgs(platform) {
   363→    const args = [];
   364→    if (fs.existsSync(FFMPEG)) {
   365→        args.push('--ffmpeg-location', BIN_DIR);
   366→    }
   367→    if (platform === 'bilibili' && fs.existsSync(COOKIES_FILE)) {
   368→        args.push('--cookies', COOKIES_FILE);
