   102→
   103→    private suspend fun downloadVideoFile(
   104→        videoUrl: String,
   105→        title: String,
   106→        outputFile: File,
   107→        onComplete: (String, String?) -> Unit
   108→    ) {
   109→        val request = okhttp3.Request.Builder()
   110→            .url(videoUrl)
   111→            .build()
   112→
   113→        val client = okhttp3.OkHttpClient.Builder()
   114→            .connectTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
   115→            .readTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
   116→            .build()
   117→
   118→        val response = client.newCall(request).execute()
   119→
   120→        if (!response.isSuccessful) {
   121→            throw Exception("HTTP ${response.code}")
   122→        }
   123→
   124→        val body = response.body ?: throw Exception("No response body")
   125→        val contentLength = body.contentLength()
   126→        val inputStream = body.byteStream()
   127→
   128→        val fileName = "${title}_${System.currentTimeMillis()}.mp4"
   129→        val finalFile = if (outputFile.exists()) File(downloadsDir, fileName) else outputFile
   130→
   131→        var bytesCopied = 0L
   132→        val buffer = ByteArray(8 * 1024)
   133→        var bytes: Int
   134→
