package com.multilanglearner.ui.home

import android.annotation.SuppressLint
import android.app.Application
import android.content.Context
import android.net.Uri
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.multilanglearner.data.db.entity.VideoEntity
import com.multilanglearner.data.network.VideoDownloadService
import com.multilanglearner.data.repository.VideoRepository
import com.multilanglearner.data.store.ThemeStore
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.File
import java.io.FileOutputStream
import javax.inject.Inject

data class HomeUiState(
    val url: String = "",
    val selectedLang: String = "en",
    val isDownloading: Boolean = false,
    val downloadProgress: Float = 0f,
    val statusText: String = "",
    val videos: List<VideoEntity> = emptyList(),
    val isFetchingInfo: Boolean = false
)

@HiltViewModel
class HomeViewModel @Inject constructor(
    @SuppressLint("StaticFieldLeak") private val application: Application,
    private val videoRepository: VideoRepository,
    private val themeStore: ThemeStore,
    private val videoDownloadService: VideoDownloadService
) : AndroidViewModel(application) {

    private val _uiState = MutableStateFlow(HomeUiState())
    val uiState: StateFlow<HomeUiState> = _uiState.asStateFlow()

    val downloadsDir: File
        get() = File(application.getExternalFilesDir(null), "videos").apply {
            if (!exists()) mkdirs()
        }

    init {
        viewModelScope.launch {
            videoRepository.getAll().collect { videos ->
                _uiState.update { it.copy(videos = videos) }
            }
        }
    }

    fun setUrl(url: String) { _uiState.update { it.copy(url = url) } }
    fun setLang(lang: String) { _uiState.update { it.copy(selectedLang = lang) } }

    fun setTheme(theme: String) { viewModelScope.launch { themeStore.setTheme(theme) } }
    fun setFontSize(size: String) { viewModelScope.launch { themeStore.setFontSize(size) } }

    /**
     * 下载视频 - 支持 B站、YouTube 等平台
     */
    fun downloadVideo(onComplete: (String, String?) -> Unit) {
        val url = _uiState.value.url.trim()

        if (url.isBlank()) {
            _uiState.update { it.copy(statusText = "请输入视频链接") }
            return
        }

        viewModelScope.launch(Dispatchers.IO) {
            try {
                _uiState.update { it.copy(isDownloading = true, isFetchingInfo = true, statusText = "正在解析视频链接...") }

                val result = videoDownloadService.getVideoInfo(url)

                _uiState.update { it.copy(isFetchingInfo = false) }

                result.onSuccess { videoInfo ->
                    _uiState.update { it.copy(statusText = "正在下载: ${videoInfo.title}") }

                    val safeTitle = videoInfo.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
                    val outputFile = File(downloadsDir, "${safeTitle}_${System.currentTimeMillis()}.mp4")

                    try {
                        downloadVideoFile(videoInfo.downloadUrl, safeTitle, outputFile, onComplete)
                    } catch (e: Exception) {
                        _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
                    }
                }.onFailure { error ->
                    _uiState.update { it.copy(isDownloading = false, statusText = "解析失败: ${error.message}\n\n建议：使用导入功能添加本地视频") }
                }

            } catch (e: Exception) {
                android.util.Log.e("HomeViewModel", "Download failed", e)
                _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
            }
        }
    }

    private suspend fun downloadVideoFile(
        videoUrl: String,
        title: String,
        outputFile: File,
        onComplete: (String, String?) -> Unit
    ) {
        val request = okhttp3.Request.Builder()
            .url(videoUrl)
            .build()

        val client = okhttp3.OkHttpClient.Builder()
            .connectTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
            .readTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
            .build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            throw Exception("HTTP ${response.code}")
        }

        val body = response.body ?: throw Exception("No response body")
        val contentLength = body.contentLength()
        val inputStream = body.byteStream()

        val fileName = "${title}_${System.currentTimeMillis()}.mp4"
        val finalFile = if (outputFile.exists()) File(downloadsDir, fileName) else outputFile

        var bytesCopied = 0L
        val buffer = ByteArray(8 * 1024)
        var bytes: Int

        inputStream.use { input ->
            FileOutputStream(finalFile).use { output ->
                while (input.read(buffer).also { bytes = it } > 0) {
                    output.write(buffer, 0, bytes)
                    bytesCopied += bytes

                    if (contentLength > 0) {
                        val progress = (bytesCopied * 100 / contentLength).toInt()
                        _uiState.update { it.copy(downloadProgress = progress / 100f, statusText = "下载中 $progress%") }
                    }
                }
            }
        }

        // 保存到数据库
        val entity = VideoEntity(
            title = title,
            filePath = finalFile.absolutePath,
            vttPath = null,
            language = _uiState.value.selectedLang,
            sourceUrl = _uiState.value.url
        )
        videoRepository.insert(entity)

        _uiState.update { it.copy(isDownloading = false, statusText = "下载完成!", url = "") }

        withContext(Dispatchers.Main) {
            onComplete(finalFile.absolutePath, null)
        }
    }

    fun importVideo(context: Context, uri: Uri, onComplete: (String, String?) -> Unit) {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                _uiState.update { it.copy(statusText = "正在导入..." ) }

                val fileName = getFileName(context, uri) ?: "import_${System.currentTimeMillis()}.mp4"
                val tempFile = File(downloadsDir, fileName)

                val inputStream = context.contentResolver.openInputStream(uri)
                val outputStream = FileOutputStream(tempFile)

                inputStream?.use { input ->
                    outputStream.use { output ->
                        input.copyTo(output)
                    }
                }

                val entity = VideoEntity(
                    title = tempFile.nameWithoutExtension,
                    filePath = tempFile.absolutePath,
                    vttPath = null,
                    language = _uiState.value.selectedLang,
                    sourceUrl = null
                )
                videoRepository.insert(entity)

                _uiState.update { it.copy(statusText = "导入完成!", url = "") }
                launch(Dispatchers.Main) { onComplete(tempFile.absolutePath, null) }
            } catch (e: Exception) {
                android.util.Log.e("MultiLangLearner", "Import failed", e)
                _uiState.update { it.copy(statusText = "导入失败: ${e.message}") }
            }
        }
    }

    private fun getFileName(context: Context, uri: Uri): String? {
        var result: String? = null
        if (uri.scheme == "content") {
            val cursor = context.contentResolver.query(uri, null, null, null, null)
            cursor?.use {
                if (it.moveToFirst()) {
                    val index = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                    if (index >= 0) result = it.getString(index)
                }
            }
        }
        if (result == null) {
            result = uri.path
            val cut = result?.lastIndexOf('/')
            if (cut != -1) {
                result = result?.substring(cut!! + 1)
            }
        }
        return result
    }
}

package com.multilanglearner.data.network

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import java.io.File
import java.io.IOException
import java.io.RandomAccessFile
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 分段下载管理器
 * 支持大文件分段下载和断点续传
 */
@Singleton
class SegmentedDownloader @Inject constructor() {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    // 每个分段的大小（5MB）
    private val SEGMENT_SIZE = 5L * 1024 * 1024

    // 最小分段大小（1MB，小于此文件不分段）
    private val MIN_SEGMENT_SIZE = 1L * 1024 * 1024

    /**
     * 下载进度回调
     */
    data class DownloadProgress(
        val bytesDownloaded: Long,
        val totalBytes: Long,
        val percent: Int,
        val speed: Long, // bytes per second
        val segmentIndex: Int,
        val totalSegments: Int
    )

    /**
     * 下载配置
     */
    data class DownloadConfig(
        val url: String,
        val outputFile: File,
        val segmentSize: Long = SEGMENT_SIZE,
        val enableResume: Boolean = true,
        val onProgress: (DownloadProgress) -> Unit = {}
    )

    /**
     * 开始分段下载
     */
    suspend fun download(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            Log.d("SegmentedDownloader", "Starting download: ${config.url}")

            // 获取文件大小
            val fileSize = getContentLength(config.url)
            if (fileSize <= 0) {
                // 不支持分段下载，使用普通下载
                Log.d("SegmentedDownloader", "Segmented download not supported, using simple download")
                return@withContext simpleDownload(config)
            }

            Log.d("SegmentedDownloader", "File size: $fileSize bytes")

            // 判断是否需要分段
            if (fileSize < MIN_SEGMENT_SIZE) {
                Log.d("SegmentedDownloader", "File too small for segmentation, using simple download")
                return@withContext simpleDownload(config)
            }

            // 计算分段数量
            val segmentCount = ((fileSize + config.segmentSize - 1) / config.segmentSize).toInt()
            Log.d("SegmentedDownloader", "Splitting into $segmentCount segments")

            // 创建临时文件
            val tempFile = File(config.outputFile.absolutePath + ".tmp")
            val raf = RandomAccessFile(tempFile, "rw")
            raf.setLength(fileSize)

            // 下载每个分段
            val downloadedSegments = if (config.enableResume) {
                loadResumeState(tempFile)
            } else {
                mutableSetOf()
            }

            var totalDownloaded = 0L
            val startTime = System.currentTimeMillis()

            for (i in 0 until segmentCount) {
                if (i in downloadedSegments) {
                    Log.d("SegmentedDownloader", "Segment $i already downloaded, skipping")
                    totalDownloaded += minOf(config.segmentSize, fileSize - i * config.segmentSize)
                    continue
                }

                val start = i * config.segmentSize
                val end = minOf(start + config.segmentSize - 1, fileSize - 1)

                Log.d("SegmentedDownloader", "Downloading segment $i: $start-$end")

                try {
                    downloadSegment(config.url, tempFile, start, end) { bytes ->
                        totalDownloaded += bytes
                        val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                        val speed = if (elapsed > 0) totalDownloaded / elapsed.toLong() else 0

                        config.onProgress(DownloadProgress(
                            bytesDownloaded = totalDownloaded,
                            totalBytes = fileSize,
                            percent = ((totalDownloaded * 100) / fileSize).toInt(),
                            speed = speed,
                            segmentIndex = i + 1,
                            totalSegments = segmentCount
                        ))
                    }

                    downloadedSegments.add(i)
                    saveResumeState(tempFile, downloadedSegments)
                } catch (e: Exception) {
                    Log.e("SegmentedDownloader", "Failed to download segment $i", e)
                    raf.close()
                    // 保存断点信息
                    saveResumeState(tempFile, downloadedSegments)
                    throw e
                }
            }

            raf.close()

            // 重命名为最终文件
            if (config.outputFile.exists()) {
                config.outputFile.delete()
            }
            tempFile.renameTo(config.outputFile)

            Log.d("SegmentedDownloader", "Download completed: ${config.outputFile.absolutePath}")
            Result.success(config.outputFile)
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 简单下载（不支持分段）
     */
    private suspend fun simpleDownload(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            val request = okhttp3.Request.Builder()
                .url(config.url)
                .build()

            val response = client.newCall(request).execute()

            if (!response.isSuccessful) {
                throw IOException("HTTP ${response.code}")
            }

            val body = response.body ?: throw IOException("No response body")
            val inputStream = body.byteStream()
            val totalBytes = body.contentLength()
            var downloadedBytes = 0L
            val startTime = System.currentTimeMillis()

            config.outputFile.outputStream().use { output ->
                val buffer = ByteArray(8 * 1024)
                var bytes: Int

                while (inputStream.read(buffer).also { bytes = it } > 0) {
                    output.write(buffer, 0, bytes)
                    downloadedBytes += bytes

                    val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                    val speed = if (elapsed > 0) (downloadedBytes / elapsed).toLong() else 0

                    if (totalBytes > 0) {
                        config.onProgress(DownloadProgress(
                            bytesDownloaded = downloadedBytes,
                            totalBytes = totalBytes,
                            percent = ((downloadedBytes * 100) / totalBytes).toInt(),
                            speed = speed,
                            segmentIndex = 1,
                            totalSegments = 1
                        ))
                    }
                }
            }

            Result.success(config.outputFile)
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Simple download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 下载单个分段
     */
    private fun downloadSegment(
        url: String,
        file: File,
        start: Long,
        end: Long,
        onBytesDownloaded: (Long) -> Unit
    ) {
        val request = okhttp3.Request.Builder()
            .url(url)
            .header("Range", "bytes=$start-$end")
            .build()

        val response = client.newCall(request).execute()

        if (response.code !in 200..299) {
            throw IOException("HTTP ${response.code} for segment $start-$end")
        }

        val inputStream = response.body?.byteStream() ?: throw IOException("No response body")
        val raf = RandomAccessFile(file, "rw")
        raf.seek(start)

        val buffer = ByteArray(8 * 1024)
        var bytes: Int
        var totalBytes = 0L

        while (inputStream.read(buffer).also { bytes = it } > 0) {
            raf.write(buffer, 0, bytes)
            totalBytes += bytes
            onBytesDownloaded(bytes.toLong())
        }

        raf.close()
        inputStream.close()
    }

    /**
     * 获取文件内容长度
     */
    private fun getContentLength(url: String): Long {
        return try {
            val request = okhttp3.Request.Builder()
                .url(url)
                .head()
                .build()

            val response = client.newCall(request).execute()

            // 检查是否支持断点续传
            val acceptRanges = response.header("Accept-Ranges") == "bytes"
            val contentLength = response.body?.contentLength() ?: 0

            if (acceptRanges && contentLength > 0) {
                contentLength
            } else {
                0
            }
        } catch (e: Exception) {
            Log.w("SegmentedDownloader", "Failed to get content length", e)
            0
        }
    }

    /**
     * 保存断点状态
     */
    private fun saveResumeState(file: File, segments: Set<Int>) {
        try {
            val stateFile = File(file.absolutePath + ".resume")
            stateFile.writeText(segments.joinToString(","))
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to save resume state", e)
        }
    }

    /**
     * 加载断点状态
     */
    private fun loadResumeState(file: File): MutableSet<Int> {
        return try {
            val stateFile = File(file.absolutePath + ".resume")
            if (stateFile.exists()) {
                val content = stateFile.readText()
                if (content.isNotBlank()) {
                    content.split(",").mapNotNull { it.toIntOrNull() }.toMutableSet()
                } else {
                    mutableSetOf()
                }
            } else {
                mutableSetOf()
            }
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to load resume state", e)
            mutableSetOf()
        }
    }

    /**
     * 清理断点状态
     */
    fun clearResumeState(file: File) {
        try {
            val stateFile = File(file.absolutePath + ".resume")
            if (stateFile.exists()) {
                stateFile.delete()
            }
            val tempFile = File(file.absolutePath + ".tmp")
            if (tempFile.exists()) {
                tempFile.delete()
            }
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to clear resume state", e)
        }
    }

    /**
     * 取消下载并清理临时文件
     */
    fun cancelDownload(outputFile: File) {
        clearResumeState(outputFile)
    }
}

