    61→
    62→    /**
    63→     * 下载视频 - 支持 B站、YouTube 等平台
    64→     */
    65→    fun downloadVideo(onComplete: (String, String?) -> Unit) {
    66→        val url = _uiState.value.url.trim()
    67→
    68→        if (url.isBlank()) {
    69→            _uiState.update { it.copy(statusText = "请输入视频链接") }
    70→            return
    71→        }
    72→
    73→        viewModelScope.launch(Dispatchers.IO) {
    74→            try {
    75→                _uiState.update { it.copy(isDownloading = true, isFetchingInfo = true, statusText = "正在解析视频链接...") }
    76→
    77→                val result = videoDownloadService.getVideoInfo(url)
    78→
    79→                _uiState.update { it.copy(isFetchingInfo = false) }
    80→
    81→                result.onSuccess { videoInfo ->
    82→                    _uiState.update { it.copy(statusText = "正在下载: ${videoInfo.title}") }
    83→
    84→                    val safeTitle = videoInfo.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
    85→                    val outputFile = File(downloadsDir, "${safeTitle}_${System.currentTimeMillis()}.mp4")
    86→
    87→                    try {
    88→                        downloadVideoFile(videoInfo.downloadUrl, safeTitle, outputFile, onComplete)
    89→                    } catch (e: Exception) {
    90→                        _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
    91→                    }
    92→                }.onFailure { error ->
    93→                    _uiState.update { it.copy(isDownloading = false, statusText = "解析失败: ${error.message}\n\n建议：使用导入功能添加本地视频") }
    94→                }
    95→
    96→            } catch (e: Exception) {
    97→                android.util.Log.e("HomeViewModel", "Download failed", e)
    98→                _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
    99→            }
   100→        }
   101→    }
   102→
   103→    private suspend fun downloadVideoFile(
   104→        videoUrl: String,
   105→        title: String,
   106→        outputFile: File,
   107→        onComplete: (String, String?) -> Unit
   108→    ) {
   109→        val request = okhttp3.Request.Builder()
   110→            .url(videoUrl)
   111→            .build()
   112→
   113→        val client = okhttp3.OkHttpClient.Builder()
   114→            .connectTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
   115→            .readTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
   116→            .build()
   117→
   118→        val response = client.newCall(request).execute()
   119→
   120→        if (!response.isSuccessful) {
   121→            throw Exception("HTTP ${response.code}")
   122→        }
   123→
   124→        val body = response.body ?: throw Exception("No response body")
   125→        val contentLength = body.contentLength()
   126→        val inputStream = body.byteStream()
   127→
   128→        val fileName = "${title}_${System.currentTimeMillis()}.mp4"
   129→        val finalFile = if (outputFile.exists()) File(downloadsDir, fileName) else outputFile
   130→
   131→        var bytesCopied = 0L
   132→        val buffer = ByteArray(8 * 1024)
   133→        var bytes: Int
   134→
   135→        inputStream.use { input ->
   136→            FileOutputStream(finalFile).use { output ->
   137→                while (input.read(buffer).also { bytes = it } > 0) {
   138→                    output.write(buffer, 0, bytes)
   139→                    bytesCopied += bytes
   140→
   141→                    if (contentLength > 0) {
   142→                        val progress = (bytesCopied * 100 / contentLength).toInt()
   143→                        _uiState.update { it.copy(downloadProgress = progress / 100f, statusText = "下载中 $progress%") }
   144→                    }
   145→                }
   146→            }
   147→        }
   148→
   149→        // 保存到数据库
   150→        val entity = VideoEntity(
   151→            title = title,
   152→            filePath = finalFile.absolutePath,
   153→            vttPath = null,
   154→            language = _uiState.value.selectedLang,
   155→            sourceUrl = _uiState.value.url
   156→        )
   157→        videoRepository.insert(entity)
   158→
   159→        _uiState.update { it.copy(isDownloading = false, statusText = "下载完成!", url = "") }
   160→
   161→        withContext(Dispatchers.Main) {
   162→            onComplete(finalFile.absolutePath, null)
   163→        }
   164→    }
