   173→
   174→                val inputStream = context.contentResolver.openInputStream(uri)
   175→                val outputStream = FileOutputStream(tempFile)
   176→
   177→                inputStream?.use { input ->
   178→                    outputStream.use { output ->
   179→                        input.copyTo(output)
   180→                    }
   181→                }
   182→
   183→                val entity = VideoEntity(
   184→                    title = tempFile.nameWithoutExtension,
   185→                    filePath = tempFile.absolutePath,
   186→                    vttPath = null,
   187→                    language = _uiState.value.selectedLang,
   188→                    sourceUrl = null
   189→                )
