   191→
   192→                _uiState.update { it.copy(statusText = "导入完成!", url = "") }
   193→                launch(Dispatchers.Main) { onComplete(tempFile.absolutePath, null) }
   194→            } catch (e: Exception) {
   195→                android.util.Log.e("MultiLangLearner", "Import failed", e)
   196→                _uiState.update { it.copy(statusText = "导入失败: ${e.message}") }
   197→            }
   198→        }
   199→    }
   200→
   201→    private fun getFileName(context: Context, uri: Uri): String? {
   202→        var result: String? = null
   203→        if (uri.scheme == "content") {
   204→            val cursor = context.contentResolver.query(uri, null, null, null, null)
   205→            cursor?.use {
   206→                if (it.moveToFirst()) {
   207→                    val index = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
   208→                    if (index >= 0) result = it.getString(index)
   209→                }
   210→            }
   211→        }
   212→        if (result == null) {
   213→            result = uri.path
   214→            val cut = result?.lastIndexOf('/')
   215→            if (cut != -1) {
   216→                result = result?.substring(cut!! + 1)
