 */
fun cancelDownload() {
    currentDownloadJob?.cancel()
    currentDownloadTask?.let { task ->
        val cancelledTask = task.copy(
            status = DownloadStatus.CANCELLED,
            completedAt = System.currentTimeMillis()
        )
        updateCurrentDownload(cancelledTask)
        addToHistory(cancelledTask)

        // 清理临时文件
        if (task.totalBytes > 0) {
            val safeTitle = task.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
            val outputFile = File(downloadsDir, "${safeTitle}_${task.createdAt}.mp4")
            segmentedDownloader.cancelDownload(outputFile)
        }
    }
    updateCurrentDownload(null)
}

