/**
 * 使用指定 API 获取 B站视频信息
 */
private suspend fun fetchBilibiliInfoWithApi(api: BilibiliApiConfig): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
    try {
        val request = Request.Builder()
            .url(api.endpoint)
            .header("User-Agent", getUserAgent())
            .header("Referer", "https://www.bilibili.com/")
            .build()

        val response = client.newCall(request).execute()
        val responseBody = response.body?.string() ?: return@withContext Result.failure(IOException("空响应"))

        Log.d(TAG, "[${api.name}] Response: ${responseBody.take(300)}")

        // 检查是否是HTML响应（API可能失效）
        if (responseBody.trim().startsWith("<!DOCTYPE") || responseBody.trim().startsWith("<html")) {
            Log.w(TAG, "[${api.name}] API returned HTML, may be invalid")
            return@withContext Result.failure(Exception("API返回HTML，可能已失效"))
        }

        val json = JSONObject(responseBody)

        // 尝试多种返回格式解析

        // 格式1: {data: {url: "...", title: "..."}}
        if (json.has("data")) {
            val data = json.getJSONObject("data")
            val videoUrl = data.optJSONArray("url")?.optString(0)
                ?: data.optString("url")
                ?: data.optString("video_url")
                ?: data.optString("playurl")
                ?: data.optString("download_url")

            val title = data.optString("title")
                ?: data.optString("name")
                ?: "B站视频"

            if (videoUrl.isNotEmpty() && videoUrl.startsWith("http")) {
                Log.d(TAG, "[${api.name}] Got video URL: $videoUrl")
                return@withContext Result.success(VideoDownloadInfo(
                    title = title,
                    downloadUrl = videoUrl,
                    cover = data.optString("pic")
                        ?: data.optString("cover")
                        ?: data.optString("img"),
                    duration = data.optLong("duration", 0L) / 1000,
                    author = data.optString("author")
                        ?: data.optString("uploader")
                        ?: data.optString("owner")?.let { ownerJson ->
                            try { JSONObject(ownerJson).optString("name") } catch(e: Exception) { null }
                        }
                ))
            }
        }

        // 格式2: {url: "...", title: "..."}
        val directUrl = json.optString("url")
            ?: json.optString("video_url")
            ?: json.optString("playurl")
            ?: json.optString("download_url")

        if (directUrl.startsWith("http")) {
            val title = json.optString("title") ?: "B站视频"
            Log.d(TAG, "[${api.name}] Got direct URL: $directUrl")
            return@withContext Result.success(VideoDownloadInfo(
                title = title,
                downloadUrl = directUrl,
                cover = json.optString("pic") ?: json.optString("cover"),
                duration = json.optLong("duration", 0L) / 1000,
                author = json.optString("author")
            ))
        }

        // 格式3: {code: 200, data: {url: "..."}} 或 {code: 200, url: "..."}
        if (json.optInt("code") == 200 || json.optInt("code") == 1) {
            val nestedData = json.optJSONObject("data")
            val videoUrl = nestedData?.optString("url")
                ?: nestedData?.optString("video_url")
                ?: json.optString("url")
                ?: json.optString("video_url")

            if (videoUrl?.startsWith("http") == true) {
                val title = nestedData?.optString("title")
                    ?: json.optString("title")
                    ?: "B站视频"
                return@withContext Result.success(VideoDownloadInfo(
                    title = title,
                    downloadUrl = videoUrl,
                    cover = nestedData?.optString("pic") ?: json.optString("pic"),
                    duration = nestedData?.optLong("duration", 0L)?.div(1000) ?: 0L
                ))
            }
        }

        // 格式4: {msg: "...", code: ...} - 可能包含错误信息
        val msg = json.optString("msg") ?: json.optString("message")
        if (msg.isNotEmpty()) {
            return@withContext Result.failure(Exception("API返回: $msg"))
        }

        // 无法解析
        return@withContext Result.failure(Exception("无法解析API响应格式"))

    } catch (e: Exception) {
        Log.e(TAG, "[${api.name}] Request failed", e)
        Result.failure(e)
    }
}

