package com.multilanglearner.di

import android.content.Context
import androidx.room.Room
import com.multilanglearner.data.db.AppDatabase
import com.multilanglearner.data.db.dao.FavoriteDao
import com.multilanglearner.data.db.dao.RegulationDao
import com.multilanglearner.data.db.dao.VideoDao
import com.multilanglearner.data.network.SegmentedDownloader
import com.multilanglearner.data.network.SegmentedTranscribeService
import com.multilanglearner.data.network.VideoDownloadService
import dagger.Module
import dagger.Provides
import dagger.hilt.InstallIn
import dagger.hilt.android.qualifiers.ApplicationContext
import dagger.hilt.components.SingletonComponent
import javax.inject.Singleton

@Module
@InstallIn(SingletonComponent::class)
object AppModule {
    @Provides
    @Singleton
    fun provideDatabase(@ApplicationContext context: Context): AppDatabase {
        return Room.databaseBuilder(context, AppDatabase::class.java, "multilang_learner.db")
            .fallbackToDestructiveMigration()
            .build()
    }

    @Provides fun provideFavoriteDao(db: AppDatabase): FavoriteDao = db.favoriteDao()
    @Provides fun provideRegulationDao(db: AppDatabase): RegulationDao = db.regulationDao()
    @Provides fun provideVideoDao(db: AppDatabase): VideoDao = db.videoDao()

    @Provides
    @Singleton
    fun provideVideoDownloadService(): VideoDownloadService = VideoDownloadService()

    @Provides
    @Singleton
    fun provideSegmentedDownloader(): SegmentedDownloader = SegmentedDownloader()
}

package com.multilanglearner.data.network

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.async
import kotlinx.coroutines.withContext
import kotlinx.coroutines.yield
import okhttp3.OkHttpClient
import java.io.File
import java.io.IOException
import java.io.RandomAccessFile
import java.util.concurrent.TimeUnit
import java.util.concurrent.atomic.AtomicBoolean
import java.util.concurrent.atomic.AtomicLong
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 分段下载管理器
 * 支持大文件分段下载和断点续传
 *
 * 功能特性：
 * - 支持大文件（>100MB）分段下载
 * - 改进的断点续传（包含校验和）
 * - 详细的进度回调（分段信息、速度、剩余时间）
 * - 并发下载优化
 * - 增强的错误处理和重试机制
 * - 支持取消下载
 */
@Singleton
class SegmentedDownloader @Inject constructor() {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    // 每个分段的大小（5MB）
    private val SEGMENT_SIZE = 5L * 1024 * 1024

    // 最小分段大小（1MB，小于此文件不分段）
    private val MIN_SEGMENT_SIZE = 1L * 1024 * 1024

    // 大文件阈值（100MB，超过此值使用更大的分段）
    private val LARGE_FILE_THRESHOLD = 100L * 1024 * 1024

    // 大文件分段大小（10MB）
    private val LARGE_SEGMENT_SIZE = 10L * 1024 * 1024

    // 最大并发下载数
    private val MAX_CONCURRENT_DOWNLOADS = 3

    // 最大重试次数
    private val MAX_RETRY_COUNT = 3

    // 重试延迟（毫秒）
    private val RETRY_DELAY_MS = 1000L

    // 当前下载的取消标志
    private val currentCancellationFlag = AtomicBoolean(false)

    /**
     * 下载进度回调
     */
    data class DownloadProgress(
        val bytesDownloaded: Long,
        val totalBytes: Long,
        val percent: Int,
        val speed: Long, // bytes per second
        val segmentIndex: Int, // 当前分段索引（1-based）
        val totalSegments: Int, // 总分段数
        val completedSegments: Set<Int>, // 已完成的分段索引集合
        val currentSegmentBytes: Long = 0, // 当前分段已下载字节数
        val currentSegmentTotal: Long = 0, // 当前分段总字节数
        val remainingTimeSeconds: Long = 0, // 预计剩余时间（秒）
        val activeConnections: Int = 1 // 当前活跃连接数
    )

    /**
     * 下载配置
     */
    data class DownloadConfig(
        val url: String,
        val outputFile: File,
        val segmentSize: Long = SEGMENT_SIZE,
        val enableResume: Boolean = true,
        val maxRetries: Int = MAX_RETRY_COUNT,
        val concurrentDownloads: Int = MAX_CONCURRENT_DOWNLOADS,
        val onProgress: (DownloadProgress) -> Unit = {},
        val onSegmentComplete: (segmentIndex: Int, success: Boolean) -> Unit = { _, _ -> }
    )

    /**
     * 分段状态信息
     */
    private data class SegmentState(
        val index: Int,
        val start: Long,
        val end: Long,
        val downloadedBytes: Long = 0,
        val isCompleted: Boolean = false,
        val checksum: Long = 0 // 简单校验和
    )

    /**
     * 断点续传状态
     */
    private data class ResumeState(
        val fileSize: Long,
        val segmentSize: Long,
        val segments: List<SegmentState>,
        val timestamp: Long = System.currentTimeMillis()
    )
    suspend fun download(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            Log.d("SegmentedDownloader", "Starting download: ${config.url}")

            // 获取文件大小
            val fileSize = getContentLength(config.url)
            if (fileSize <= 0) {
                // 不支持分段下载，使用普通下载
                Log.d("SegmentedDownloader", "Segmented download not supported, using simple download")
                return@withContext simpleDownload(config)
            }

            Log.d("SegmentedDownloader", "File size: $fileSize bytes")

            // 判断是否需要分段
            if (fileSize < MIN_SEGMENT_SIZE) {
                Log.d("SegmentedDownloader", "File too small for segmentation, using simple download")
                return@withContext simpleDownload(config)
            }

            // 计算分段数量
            val segmentCount = ((fileSize + config.segmentSize - 1) / config.segmentSize).toInt()
            Log.d("SegmentedDownloader", "Splitting into $segmentCount segments")

            // 创建临时文件
            val tempFile = File(config.outputFile.absolutePath + ".tmp")
            val raf = RandomAccessFile(tempFile, "rw")
            raf.setLength(fileSize)

            // 下载每个分段
            val downloadedSegments = if (config.enableResume) {
                loadResumeState(tempFile)
            } else {
                mutableSetOf()
            }

            var totalDownloaded = 0L
            val startTime = System.currentTimeMillis()

            for (i in 0 until segmentCount) {
                if (i in downloadedSegments) {
                    Log.d("SegmentedDownloader", "Segment $i already downloaded, skipping")
                    totalDownloaded += minOf(config.segmentSize, fileSize - i * config.segmentSize)
                    continue
                }

                val start = i * config.segmentSize
                val end = minOf(start + config.segmentSize - 1, fileSize - 1)

                Log.d("SegmentedDownloader", "Downloading segment $i: $start-$end")

                try {
                    downloadSegment(config.url, tempFile, start, end) { bytes ->
                        totalDownloaded += bytes
                        val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                        val speed = if (elapsed > 0) totalDownloaded / elapsed.toLong() else 0

                        config.onProgress(DownloadProgress(
                            bytesDownloaded = totalDownloaded,
                            totalBytes = fileSize,
                            percent = ((totalDownloaded * 100) / fileSize).toInt(),
                            speed = speed,
                            segmentIndex = i + 1,
                            totalSegments = segmentCount
                        ))
                    }

                    downloadedSegments.add(i)
                    saveResumeState(tempFile, downloadedSegments)
                } catch (e: Exception) {
                    Log.e("SegmentedDownloader", "Failed to download segment $i", e)
                    raf.close()
                    // 保存断点信息
                    saveResumeState(tempFile, downloadedSegments)
                    throw e
                }
            }

            raf.close()

            // 重命名为最终文件
            if (config.outputFile.exists()) {
                config.outputFile.delete()
            }
            tempFile.renameTo(config.outputFile)

            Log.d("SegmentedDownloader", "Download completed: ${config.outputFile.absolutePath}")
            Result.success(config.outputFile)
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 简单下载（不支持分段）
     */
    private suspend fun simpleDownload(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            val request = okhttp3.Request.Builder()
                .url(config.url)
                .build()

            val response = client.newCall(request).execute()

            if (!response.isSuccessful) {
                throw IOException("HTTP ${response.code}")
            }

            val body = response.body ?: throw IOException("No response body")
            val inputStream = body.byteStream()
            val totalBytes = body.contentLength()
            var downloadedBytes = 0L
            val startTime = System.currentTimeMillis()

            config.outputFile.outputStream().use { output ->
                val buffer = ByteArray(8 * 1024)
                var bytes: Int

                while (inputStream.read(buffer).also { bytes = it } > 0) {
                    output.write(buffer, 0, bytes)
                    downloadedBytes += bytes

                    val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                    val speed = if (elapsed > 0) (downloadedBytes / elapsed).toLong() else 0

                    if (totalBytes > 0) {
                        config.onProgress(DownloadProgress(
                            bytesDownloaded = downloadedBytes,
                            totalBytes = totalBytes,
                            percent = ((downloadedBytes * 100) / totalBytes).toInt(),
                            speed = speed,
                            segmentIndex = 1,
                            totalSegments = 1
                        ))
                    }
                }
            }

            Result.success(config.outputFile)
