    }

    // AI Settings Bottom Sheet
    if (showAISettings) {
        com.multilanglearner.ui.ai.AISettingsSheet(onDismiss = { showAISettings = false })
    }

    // Assistant Bottom Sheet
    if (showAssistant) {
        com.multilanglearner.ui.assistant.AssistantSheet(onDismiss = { showAssistant = false })
    }

    // Theme Dialog
    if (showThemeDialog) {
        com.multilanglearner.ui.component.ThemeDialog(
            onDismiss = { showThemeDialog = false },
            onThemeSelected = { viewModel.setTheme(it) },
            onFontSizeSelected = { viewModel.setFontSize(it) }
