package com.multilanglearner.ui.player

import android.app.Application
import android.speech.tts.TextToSpeech
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.multilanglearner.data.network.AIService
import com.multilanglearner.data.network.DictionaryService
import com.multilanglearner.data.network.WhisperService
import com.multilanglearner.data.repository.FavoriteRepository
import com.multilanglearner.data.store.AIConfigStore
import com.multilanglearner.domain.model.*
import com.multilanglearner.domain.util.VttParser
import com.multilanglearner.domain.util.WordAligner
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import kotlinx.serialization.json.Json
import java.io.File
import java.util.Locale
import javax.inject.Inject

data class PlayerUiState(
    val subtitles: List<SubtitleCue> = emptyList(),
    val wordTimings: List<WordTimestamp> = emptyList(),
    val currentCueIndex: Int = -1,
    val currentPositionMs: Long = 0,
    val mode: String = "learn", // "learn" or "dictation"
    val currentLang: String = "en",
    val statusText: String = "加载中...",
    val isTranscribing: Boolean = false,
    // Word card
    val showWordCard: Boolean = false,
    val wordCardData: WordCardData? = null,
    val currentSentence: String = "",
    // AI analysis
    val aiAnalysisResult: String? = null,
    val isAnalyzing: Boolean = false,
    // Dictation
    val dictationIndex: Int = 0
)

@HiltViewModel
class PlayerViewModel @Inject constructor(
    application: Application,
    private val favoriteRepository: FavoriteRepository,
    private val aiConfigStore: AIConfigStore,
    private val aiService: AIService,
    private val dictionaryService: DictionaryService,
    private val whisperService: WhisperService
) : AndroidViewModel(application) {

    private val _uiState = MutableStateFlow(PlayerUiState())
    val uiState: StateFlow<PlayerUiState> = _uiState.asStateFlow()

    private var tts: TextToSpeech? = null
    private val json = Json { ignoreUnknownKeys = true }

    init {
        tts = TextToSpeech(application) { status ->
            if (status == TextToSpeech.SUCCESS) {
                tts?.language = Locale.US
            }
        }
    }

    fun loadSubtitles(videoPath: String, subtitlePath: String?) {
        viewModelScope.launch(Dispatchers.IO) {
            // Try loading VTT subtitle
            val vttPath = subtitlePath ?: findExistingSubtitle(videoPath)
            if (vttPath != null) {
                val file = File(vttPath)
                if (file.exists()) {
                    val content = file.readText()
                    val subs = VttParser.parse(content)
                    if (subs.isNotEmpty()) {
                        _uiState.update { it.copy(
                            subtitles = subs,
                            statusText = "已加载 ${subs.size} 条字幕"
                        )}
                        // Load word timestamps if available
                        loadWordTimestamps(vttPath)
                        return@launch
                    }
                }
            }
            _uiState.update { it.copy(statusText = "无字幕文件，请在 AI 设置中配置 Groq Whisper 后重新转录") }
        }
    }

    private fun findExistingSubtitle(videoPath: String): String? {
        val base = videoPath.substringBeforeLast(".")
        for (ext in listOf(".vtt", ".srt")) {
            val f = File(base + ext)
            if (f.exists()) return f.absolutePath
        }
        // Check with language suffix
        val dir = File(videoPath).parentFile ?: return null
        val name = File(videoPath).nameWithoutExtension
        dir.listFiles()?.forEach { f ->
            if (f.name.startsWith(name) && f.extension == "vtt") return f.absolutePath
        }
        return null
    }

    private fun loadWordTimestamps(vttPath: String) {
        val wtsPath = vttPath.replace(Regex("\\.vtt$"), ".wordts.json")
        val wtsFile = File(wtsPath)
        if (wtsFile.exists()) {
            try {
                val timings: List<WordTimestamp> = json.decodeFromString(wtsFile.readText())
                _uiState.update { it.copy(wordTimings = timings) }
            } catch (_: Exception) {}
        }
    }

    /** Called every 30ms from the player to sync subtitles */
    fun updatePosition(positionMs: Long) {
        _uiState.update { it.copy(currentPositionMs = positionMs) }
        val subs = _uiState.value.subtitles
        if (subs.isEmpty()) return

        // Binary search for current cue (ported from renderer.js)
        var lo = 0; var hi = subs.size - 1; var idx = -1
        while (lo <= hi) {
            val mid = (lo + hi) ushr 1
            when {
                positionMs < subs[mid].startMs -> hi = mid - 1
                positionMs > subs[mid].endMs -> lo = mid + 1
                else -> { idx = mid; break }
            }
        }
        // Gap handling: find next cue within 0.5s
        if (idx < 0) {
            for (i in subs.indices) {
                if (subs[i].startMs > positionMs) {
                    idx = if (subs[i].startMs - positionMs < 500) i else if (i > 0) i - 1 else 0
                    break
                }
            }
            if (idx < 0) idx = subs.size - 1
        }

        if (idx != _uiState.value.currentCueIndex) {
            _uiState.update { it.copy(
                currentCueIndex = idx,
                currentSentence = subs[idx].text,
                showWordCard = false,
                aiAnalysisResult = null
            )}
        }
    }

    /** Retranscribe - 使用分段转录支持大文件 */
    fun retranscribe(videoPath: String) {
        viewModelScope.launch(Dispatchers.IO) {
            // Delete existing subtitle files
            val base = videoPath.substringBeforeLast(".")
            listOf(".vtt", ".wordts.json").forEach { ext ->
                val f = File(base + ext)
                if (f.exists()) f.delete()
            }
            // Also check language-suffixed vtt
            File(videoPath).parentFile?.listFiles()?.forEach { f ->
                val name = File(videoPath).nameWithoutExtension
                if (f.name.startsWith(name) && (f.extension == "vtt" || f.name.endsWith(".wordts.json"))) {
                    f.delete()
                }
            }

            _uiState.update { it.copy(
                subtitles = emptyList(),
                wordTimings = emptyList(),
                currentCueIndex = -1,
                isTranscribing = true,
                statusText = "正在准备转录..."
            )}

            val config = aiConfigStore.config.first()

            // Check Groq API Key
            val hasGroqKey = config.groqApiKey.isNotBlank() ||
                             (config.provider == "groq" && config.apiKey.isNotBlank())

            if (!hasGroqKey) {
                _uiState.update { it.copy(isTranscribing = false, statusText = "请先在 AI 设置中配置 Groq Whisper API Key") }
                return@launch
            }

            val videoFile = File(videoPath)

            // 使用分段转录服务
            val result = segmentedTranscribeService.transcribeVideo(
                videoFile,
                config
            ) { current, total, message ->
                _uiState.update { it.copy(statusText = message) }
            }

            if (result.success && result.text.isNotBlank()) {
                // Build VTT from word timestamps
                val vttPath = base + ".vtt"
                val wtsPath = base + ".wordts.json"
                val vttBuilder = StringBuilder("WEBVTT\n\n")
                val allWordTimings = mutableListOf<WordTimestamp>()

                if (result.words.isNotEmpty()) {
                    var curWords = mutableListOf<WordTimestamp>()
                    for (wt in result.words) {
                        curWords.add(wt)
                        if (wt.w.trim().matches(Regex(".*[.!?。！？]$")) && curWords.isNotEmpty()) {
                            val sentText = curWords.joinToString(" ") { it.w }
                            val sStart = curWords.first().s
                            val sEnd = curWords.last().e
                            vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
                            allWordTimings.addAll(curWords)
                            curWords = mutableListOf()
                        }
                    }
                    if (curWords.isNotEmpty()) {
                        val sentText = curWords.joinToString(" ") { it.w }
                        val sStart = curWords.first().s
                        val sEnd = curWords.last().e
                        vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
                        allWordTimings.addAll(curWords)
                    }
                }

                // Save files
                File(vttPath).writeText(vttBuilder.toString())
                if (allWordTimings.isNotEmpty()) {
                    File(wtsPath).writeText(json.encodeToString(kotlinx.serialization.builtins.ListSerializer(WordTimestamp.serializer()), allWordTimings))
                }

                // Reload
                val subs = VttParser.parse(vttBuilder.toString())
                _uiState.update { it.copy(
                    subtitles = subs,
                    wordTimings = allWordTimings,
                    isTranscribing = false,
                    statusText = "转录完成，共 ${subs.size} 条字幕"
                )}
            } else {
                _uiState.update { it.copy(isTranscribing = false, statusText = result.error) }
            }
        }
    }

    fun setMode(mode: String) {
        _uiState.update { it.copy(mode = mode, dictationIndex = _uiState.value.currentCueIndex.coerceAtLeast(0)) }
    }

    fun setLang(lang: String) {
        _uiState.update { it.copy(currentLang = lang) }
        val locale = LANGUAGES.find { it.code == lang }?.ttsLocale ?: "en-US"
        tts?.language = Locale.forLanguageTag(locale)
    }

    /** Look up a word - ported from renderer.js showWordInline() */
    fun lookupWord(word: String) {
        _uiState.update { it.copy(showWordCard = true, wordCardData = WordCardData(word = word, translation = "查询中...")) }
        speak(word)

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val context = _uiState.value.currentSentence

            // Parallel lookups
            val aiConfig = aiConfigStore.config.first()
            val aiTransPromise = launch { aiTranslateWord(word, context, lang, aiConfig) }

            val cardData = when (lang) {
                "en" -> {
                    val online = dictionaryService.lookupEnglish(word)
                    val translation = dictionaryService.translate(word, "en")
                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
                    WordCardData(
                        word = word,
                        phonetic = online?.phonetic ?: "",
                        translation = aiTrans ?: translation ?: online?.translation ?: "未找到释义",
                        definitions = online?.definitions ?: emptyList(),
                        examples = online?.examples ?: emptyList()
                    )
                }
                "ja" -> {
                    val online = dictionaryService.lookupJapanese(word)
                    val translation = dictionaryService.translate(word, "ja")
                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
                    WordCardData(
                        word = word,
                        phonetic = online?.phonetic ?: "",
                        translation = aiTrans ?: translation ?: "未找到释义",
                        definitions = online?.definitions ?: emptyList()
                    )
                }
                else -> {
                    val translation = dictionaryService.translate(word, lang)
                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
                    WordCardData(
                        word = word,
                        translation = aiTrans ?: translation ?: "未找到释义"
                    )
                }
            }
            _uiState.update { it.copy(wordCardData = cardData) }
        }
    }

    private suspend fun aiTranslateWord(word: String, context: String, lang: String, config: AIConfig): String? {
        val langName = LANGUAGES.find { it.code == lang }?.name ?: "英语"
        val prompt = "将${langName}「${word}」翻译为中文。${if (context.isNotBlank()) "语境:\"$context\"。" else ""}只回复中文释义，多义项用/分隔，不要音译。"
        return aiService.chat(config, prompt)
    }

    fun hideWordCard() { _uiState.update { it.copy(showWordCard = false) } }

    /** AI analyze sentence - ported from main.js ai-analyze-sentence */
    fun analyzeSentence() {
        val sentence = _uiState.value.currentSentence
        if (sentence.isBlank()) return
        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }

        viewModelScope.launch(Dispatchers.IO) {
            val lang = _uiState.value.currentLang
            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
            val config = aiConfigStore.config.first()
            val prompt = """分析${langName}句子："$sentence"
【翻译】中文翻译
【语法】1-2个关键语法点
【重点词汇】2-3个重要词汇及释义"""
            val result = aiService.chat(config, prompt)
            _uiState.update { it.copy(
                isAnalyzing = false,
                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
            )}
        }
    }

    /** Favorite operations */
    suspend fun isFavorite(word: String): Boolean {
        return favoriteRepository.isFavorite(word, _uiState.value.currentLang)
    }

    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
        viewModelScope.launch {
            val lang = _uiState.value.currentLang
            if (favoriteRepository.isFavorite(word, lang)) {
                favoriteRepository.remove(word, lang)
            } else {
                favoriteRepository.add(word, lang, phonetic, translation, _uiState.value.currentSentence)
            }
        }
    }

    /** TTS */
    fun speak(text: String) {
        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, "word_tts")
    }

    /** Dictation */
    fun nextDictation() {
        val nextIdx = (_uiState.value.dictationIndex + 1).coerceAtMost(_uiState.value.subtitles.size - 1)
        _uiState.update { it.copy(dictationIndex = nextIdx) }
    }

    /** Get aligned word timings for current cue */
    fun getAlignedTimings(words: List<String>): List<WordTimestamp?> {
        val state = _uiState.value
        val cueIdx = state.currentCueIndex
        if (cueIdx < 0 || cueIdx >= state.subtitles.size || state.wordTimings.isEmpty()) {
            return List(words.size) { null }
        }
        val cue = state.subtitles[cueIdx]
        return WordAligner.alignWords(words, state.wordTimings, cue.startMs / 1000.0, cue.endMs / 1000.0)
    }

    override fun onCleared() {
        tts?.shutdown()
        super.onCleared()
    }
}

package com.multilanglearner.data.network

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.Binder
import android.os.Build
import android.os.IBinder
import androidx.core.app.NotificationCompat
import dagger.hilt.android.AndroidEntryPoint
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import java.io.File
import javax.inject.Inject

/**
 * 视频前台下载服务
 * 支持后台下载、通知栏进度显示、暂停/继续/取消
 */
@AndroidEntryPoint
class VideoDownloadForegroundService : Service() {

    @Inject
    lateinit var segmentedDownloader: SegmentedDownloader

    private val serviceScope = CoroutineScope(SupervisorJob() + Dispatchers.IO)
    private val binder = DownloadBinder()

    // 下载任务管理
    private val downloadJobs = mutableMapOf<String, DownloadTask>()
    private val _downloadTasks = MutableStateFlow<List<DownloadTask>>(emptyList())
    val downloadTasks: StateFlow<List<DownloadTask>> = _downloadTasks.asStateFlow()

    companion object {
        const val CHANNEL_ID = "video_download_channel"
        const val NOTIFICATION_ID = 1001
        const val ACTION_START_DOWNLOAD = "action_start_download"
        const val ACTION_PAUSE_DOWNLOAD = "action_pause_download"
        const val ACTION_RESUME_DOWNLOAD = "action_resume_download"
        const val ACTION_CANCEL_DOWNLOAD = "action_cancel_download"
        const val EXTRA_TASK_ID = "task_id"
        const val EXTRA_URL = "url"
        const val EXTRA_OUTPUT_PATH = "output_path"
        const val EXTRA_TITLE = "title"

        fun startDownload(context: Context, taskId: String, url: String, outputPath: String, title: String) {
            val intent = Intent(context, VideoDownloadForegroundService::class.java).apply {
                action = ACTION_START_DOWNLOAD
                putExtra(EXTRA_TASK_ID, taskId)
                putExtra(EXTRA_URL, url)
                putExtra(EXTRA_OUTPUT_PATH, outputPath)
                putExtra(EXTRA_TITLE, title)
            }
            context.startService(intent)
        }

        fun pauseDownload(context: Context, taskId: String) {
            val intent = Intent(context, VideoDownloadForegroundService::class.java).apply {
                action = ACTION_PAUSE_DOWNLOAD
                putExtra(EXTRA_TASK_ID, taskId)
            }
            context.startService(intent)
        }

        fun resumeDownload(context: Context, taskId: String) {
            val intent = Intent(context, VideoDownloadForegroundService::class.java).apply {
                action = ACTION_RESUME_DOWNLOAD
                putExtra(EXTRA_TASK_ID, taskId)
            }
            context.startService(intent)
        }

        fun cancelDownload(context: Context, taskId: String) {
            val intent = Intent(context, VideoDownloadForegroundService::class.java).apply {
                action = ACTION_CANCEL_DOWNLOAD
                putExtra(EXTRA_TASK_ID, taskId)
            }
            context.startService(intent)
        }
    }

    override fun onCreate() {
        super.onCreate()
        createNotificationChannel()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        when (intent?.action) {
            ACTION_START_DOWNLOAD -> {
                val taskId = intent.getStringExtra(EXTRA_TASK_ID) ?: return START_NOT_STICKY
                val url = intent.getStringExtra(EXTRA_URL) ?: return START_NOT_STICKY
                val outputPath = intent.getStringExtra(EXTRA_OUTPUT_PATH) ?: return START_NOT_STICKY
                val title = intent.getStringExtra(EXTRA_TITLE) ?: "视频下载"
                startDownloadTask(taskId, url, outputPath, title)
            }
            ACTION_PAUSE_DOWNLOAD -> {
                val taskId = intent.getStringExtra(EXTRA_TASK_ID) ?: return START_NOT_STICKY
                pauseTask(taskId)
            }
            ACTION_RESUME_DOWNLOAD -> {
                val taskId = intent.getStringExtra(EXTRA_TASK_ID) ?: return START_NOT_STICKY
                resumeTask(taskId)
            }
            ACTION_CANCEL_DOWNLOAD -> {
                val taskId = intent.getStringExtra(EXTRA_TASK_ID) ?: return START_NOT_STICKY
                cancelTask(taskId)
            }
        }
        return START_STICKY
    }

    override fun onBind(intent: Intent?): IBinder {
        return binder
    }

    override fun onDestroy() {
        super.onDestroy()
        serviceScope.cancel()
        // 取消所有下载任务
        downloadJobs.values.forEach { it.job?.cancel() }
        downloadJobs.clear()
    }

    /**
     * 创建通知渠道
     */
    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "视频下载",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "显示视频下载进度"
                setShowBadge(false)
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    /**
     * 开始下载任务
     */
    private fun startDownloadTask(taskId: String, url: String, outputPath: String, title: String) {
        // 检查是否已存在
        if (downloadJobs.containsKey(taskId)) {
            return
        }

        val outputFile = File(outputPath)
        val task = DownloadTask(
            id = taskId,
            url = url,
            title = title,
            outputPath = outputPath,
            status = DownloadStatus.DOWNLOADING
        )

        downloadJobs[taskId] = task
        updateTasksList()

        // 启动前台服务
        startForeground(NOTIFICATION_ID, createNotification(task))

        // 启动下载协程
        val job = serviceScope.launch {
            try {
                segmentedDownloader.download(
                    SegmentedDownloader.DownloadConfig(
                        url = url,
                        outputFile = outputFile,
                        onProgress = { progress ->
                            updateTaskProgress(taskId, progress)
                            updateNotification()
                        }
                    )
                ).onSuccess { file ->
                    completeTask(taskId, file)
                }.onFailure { error ->
                    failTask(taskId, error)
                }
            } catch (e: CancellationException) {
                // 任务被取消
                pauseTask(taskId)
            } catch (e: Exception) {
                failTask(taskId, e)
            }
        }

        task.job = job
        updateTasksList()
    }

    /**
     * 暂停任务
     */
    private fun pauseTask(taskId: String) {
        downloadJobs[taskId]?.let { task ->
            task.job?.cancel()
            task.status = DownloadStatus.PAUSED
            updateTasksList()
            updateNotification()
        }
    }

    /**
     * 恢复任务
     */
    private fun resumeTask(taskId: String) {
        downloadJobs[taskId]?.let { task ->
            task.status = DownloadStatus.DOWNLOADING
            updateTasksList()
            updateNotification()

            val outputFile = File(task.outputPath)
            val job = serviceScope.launch {
                try {
                    segmentedDownloader.download(
                        SegmentedDownloader.DownloadConfig(
                            url = task.url,
                            outputFile = outputFile,
                            enableResume = true,
                            onProgress = { progress ->
                                updateTaskProgress(taskId, progress)
                                updateNotification()
                            }
                        )
                    ).onSuccess { file ->
                        completeTask(taskId, file)
                    }.onFailure { error ->
                        failTask(taskId, error)
                    }
                } catch (e: CancellationException) {
                    pauseTask(taskId)
                } catch (e: Exception) {
                    failTask(taskId, e)
                }
            }
            task.job = job
            updateTasksList()
        }
    }

    /**
     * 取消任务
     */
    private fun cancelTask(taskId: String) {
        downloadJobs[taskId]?.let { task ->
            task.job?.cancel()
            task.status = DownloadStatus.CANCELLED
            segmentedDownloader.cancelDownload(File(task.outputPath))
            downloadJobs.remove(taskId)
            updateTasksList()
            updateNotification()

            // 如果没有其他任务，停止前台服务
            if (downloadJobs.isEmpty()) {
                stopForeground(STOP_FOREGROUND_REMOVE)
                stopSelf()
            }
        }
    }

    /**
     * 更新任务进度
     */
    private fun updateTaskProgress(taskId: String, progress: SegmentedDownloader.DownloadProgress) {
        downloadJobs[taskId]?.let { task ->
            task.progress = progress
            task.currentBytes = progress.bytesDownloaded
            task.totalBytes = progress.totalBytes
            task.speed = progress.speed
            updateTasksList()
        }
    }

    /**
     * 任务完成
     */
    private fun completeTask(taskId: String, file: File) {
        downloadJobs[taskId]?.let { task ->
            task.status = DownloadStatus.COMPLETED
            task.progress = SegmentedDownloader.DownloadProgress(
                bytesDownloaded = task.totalBytes,
                totalBytes = task.totalBytes,
                percent = 100,
                speed = 0,
                segmentIndex = task.progress?.totalSegments ?: 1,
                totalSegments = task.progress?.totalSegments ?: 1
            )
            updateTasksList()
            updateNotification()

            // 延迟移除任务
            serviceScope.launch {
                delay(5000)
                downloadJobs.remove(taskId)
                updateTasksList()
                if (downloadJobs.isEmpty()) {
                    stopForeground(STOP_FOREGROUND_REMOVE)
                    stopSelf()
                }
            }
        }
    }

    /**
     * 任务失败
     */
    private fun failTask(taskId: String, error: Throwable) {
        downloadJobs[taskId]?.let { task ->
            task.status = DownloadStatus.FAILED
            task.error = error.message
            updateTasksList()
            updateNotification()
        }
    }

    /**
     * 更新任务列表
     */
    private fun updateTasksList() {
        _downloadTasks.value = downloadJobs.values.toList()
    }

    /**
     * 创建通知
     */
    private fun createNotification(task: DownloadTask): Notification {
        val progress = task.progress
        val percent = progress?.percent ?: 0
        val contentText = when (task.status) {
            DownloadStatus.DOWNLOADING -> {
                val speedText = formatSpeed(task.speed)
                val sizeText = formatSize(task.currentBytes, task.totalBytes)
                "下载中: $sizeText ($speedText)"
            }
            DownloadStatus.PAUSED -> "已暂停"
            DownloadStatus.COMPLETED -> "下载完成"
            DownloadStatus.FAILED -> "下载失败: ${task.error}"
            DownloadStatus.CANCELLED -> "已取消"
        }

        // 暂停/继续按钮
        val pauseResumeAction = if (task.status == DownloadStatus.DOWNLOADING) {
            NotificationCompat.Action.Builder(
                android.R.drawable.ic_media_pause,
                "暂停",
                createPendingIntent(ACTION_PAUSE_DOWNLOAD, task.id)
            ).build()
        } else {
            NotificationCompat.Action.Builder(
                android.R.drawable.ic_media_play,
                "继续",
                createPendingIntent(ACTION_RESUME_DOWNLOAD, task.id)
            ).build()
        }

        // 取消按钮
        val cancelAction = NotificationCompat.Action.Builder(
            android.R.drawable.ic_delete,
            "取消",
            createPendingIntent(ACTION_CANCEL_DOWNLOAD, task.id)
        ).build()

        return NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle(task.title)
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.stat_sys_download)
            .setOngoing(task.status == DownloadStatus.DOWNLOADING)
            .setAutoCancel(false)
            .addAction(pauseResumeAction)
            .addAction(cancelAction)
            .setProgress(100, percent, task.status == DownloadStatus.DOWNLOADING && progress == null)
            .build()
    }

    /**
     * 更新通知
     */
    private fun updateNotification() {
        if (downloadJobs.isEmpty()) {
            return
        }

        // 显示最新的下载任务
        val latestTask = downloadJobs.values.last()
        val notification = createNotification(latestTask)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    /**
     * 创建 PendingIntent
     */
    private fun createPendingIntent(action: String, taskId: String): PendingIntent {
        val intent = Intent(this, VideoDownloadForegroundService::class.java).apply {
            this.action = action
            putExtra(EXTRA_TASK_ID, taskId)
        }
        return PendingIntent.getService(
            this,
            taskId.hashCode(),
            intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )
    }

    /**
     * 格式化速度
     */
    private fun formatSpeed(bytesPerSecond: Long): String {
        return when {
            bytesPerSecond < 1024 -> "${bytesPerSecond}B/s"
            bytesPerSecond < 1024 * 1024 -> "${bytesPerSecond / 1024}KB/s"
            else -> "${bytesPerSecond / (1024 * 1024)}MB/s"
        }
    }

    /**
     * 格式化大小
     */
    private fun formatSize(current: Long, total: Long): String {
        fun formatSize(bytes: Long): String {
            return when {
                bytes < 1024 -> "${bytes}B"
                bytes < 1024 * 1024 -> "${bytes / 1024}KB"
                bytes < 1024 * 1024 * 1024 -> "${bytes / (1024 * 1024)}MB"
                else -> "${bytes / (1024 * 1024 * 1024)}GB"
            }
        }
        return "${formatSize(current)}/${formatSize(total)}"
    }

    /**
     * Binder 用于客户端获取服务实例
     */
    inner class DownloadBinder : Binder() {
        fun getService(): VideoDownloadForegroundService = this@VideoDownloadForegroundService
    }

    /**
     * 下载任务数据类
     */
    data class DownloadTask(
        val id: String,
        val url: String,
        val title: String,
        val outputPath: String,
        var status: DownloadStatus = DownloadStatus.DOWNLOADING,
        var progress: SegmentedDownloader.DownloadProgress? = null,
        var currentBytes: Long = 0,
        var totalBytes: Long = 0,
        var speed: Long = 0,
        var error: String? = null,
        var job: Job? = null
    )

    /**
     * 下载状态枚举
     */
    enum class DownloadStatus {
        DOWNLOADING,
        PAUSED,
        COMPLETED,
        FAILED,
        CANCELLED
    }
}

